import { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';

const Navbar = () => {
  const [isScrolled, setIsScrolled] = useState(false);
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 50);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const navLinks = [
    { name: 'Home', path: '/' },
    { name: 'Properties', path: '/properties' },
    { name: 'EMI Calculator', path: '/emi-calculator' },
    { name: 'Contact', path: '/contact' },
  ];

  return (
    <nav className={`fixed top-0 w-full z-50 transition-all duration-500 ${
      isScrolled ? 'glass-nav py-3' : 'bg-transparent py-5'
    }`}>
      <div className="container-custom">
        <div className="flex justify-between items-center">
          <Link to="/" className="text-2xl font-bold">
            <span className="text-white">Swabhagya</span>
            <span className="text-[#d4af37]"> Realty</span>
          </Link>
          
          <div className="hidden md:flex space-x-8">
            {navLinks.map((link) => (
              <Link
                key={link.path}
                to={link.path}
                className={`transition-colors duration-300 font-medium ${
                  location.pathname === link.path 
                    ? 'text-[#d4af37]' 
                    : 'text-white hover:text-[#d4af37]'
                }`}
              >
                {link.name}
              </Link>
            ))}
          </div>
          
          <div className="flex gap-3">
            <Link 
              to="/login"
              className="text-white hover:text-[#d4af37] transition px-4 py-2"
            >
              Login
            </Link>
            <a 
              href="https://wa.me/919876543210"
              target="_blank"
              rel="noopener noreferrer"
              className="bg-[#d4af37] text-[#1a2332] px-5 py-2 rounded-lg hover:bg-opacity-90 transition font-semibold"
            >
              Enquire Now
            </a>
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
